"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[5016],{77793(n,i,t){t.r(i),t.d(i,{assets:()=>o,contentTitle:()=>a,default:()=>u,frontMatter:()=>l,metadata:()=>r,toc:()=>d});const r=JSON.parse('{"id":"cpp11/initializer-list","title":"std::initializer_list","description":"C++11 std::initializer_list \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp11/23-initializer-list.md","sourceDirName":"cpp11","slug":"/cpp11/23-initializer-list","permalink":"/LearnModernCpp/docs/cpp11/23-initializer-list","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp11","permalink":"/LearnModernCpp/docs/tags/cpp-11"},{"inline":true,"label":"initializer_list","permalink":"/LearnModernCpp/docs/tags/initializer-list"}],"version":"current","sidebarPosition":24,"frontMatter":{"sidebar_position":24,"slug":"23-initializer-list","title":"std::initializer_list","description":"C++11 std::initializer_list \u6559\u5b66\u793a\u4f8b","tags":["cpp11","initializer_list"]},"sidebar":"docs","previous":{"title":"\u7c7b\u578b\u7279\u5f81 (Type Traits)","permalink":"/LearnModernCpp/docs/cpp11/22-type-traits"},"next":{"title":"\u667a\u80fd\u6307\u9488 (unique_ptr\u3001shared_ptr\u3001weak_ptr)","permalink":"/LearnModernCpp/docs/cpp11/40-smart-pointers"}}');var s=t(74848),e=t(28453);const l={sidebar_position:24,slug:"23-initializer-list",title:"std::initializer_list",description:"C++11 std::initializer_list \u6559\u5b66\u793a\u4f8b",tags:["cpp11","initializer_list"]},a="std::initializer_list",o={},d=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function c(n){const i={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,e.R)(),...n.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(i.header,{children:(0,s.jsx)(i.h1,{id:"stdinitializer_list",children:"std::initializer_list"})}),"\n",(0,s.jsx)(i.p,{children:"C++11 \u6807\u51c6\u5f15\u5165\u7684 std::initializer_list \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,s.jsx)(i.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,s.jsx)(i.pre,{children:(0,s.jsx)(i.code,{className:"language-cpp",metastring:'title="cpp11/23_initializer_list.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: std::initializer_list\r\n * \u6240\u5c5e\u6807\u51c6: C++11\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: std::initializer_list<T> \u662f\u4e00\u4e2a\u8f7b\u91cf\u7ea7\u4ee3\u7406\u5bf9\u8c61\uff0c\r\n *          \u7528\u4e8e\u8bbf\u95ee\u82b1\u62ec\u53f7 {} \u521d\u59cb\u5316\u5217\u8868\u4e2d\u7684\u5143\u7d20\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: C++03 \u4e2d\u6ca1\u6709\u6807\u51c6\u65b9\u6cd5\u652f\u6301 vector<int> v = {1,2,3}\r\n *   \u8fd9\u6837\u7684\u8bed\u6cd5\u3002initializer_list \u4f7f\u5bb9\u5668\u548c\u81ea\u5b9a\u4e49\u7c7b\u578b\u53ef\u4ee5\u63a5\u53d7\r\n *   \u82b1\u62ec\u53f7\u521d\u59cb\u5316\u5217\u8868\u4f5c\u4e3a\u53c2\u6570\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - initializer_list \u662f\u4e00\u4e2a\u8f7b\u91cf\u7ea7\u89c6\u56fe\uff08\u6307\u9488+\u5927\u5c0f\uff09\uff0c\u4e0d\u62e5\u6709\u6570\u636e\r\n *   - \u5e95\u5c42\u6570\u636e\u662f const \u6570\u7ec4\uff0c\u5143\u7d20\u4e0d\u53ef\u4fee\u6539\r\n *   - \u652f\u6301 begin()/end()/size()\r\n *   - \u82b1\u62ec\u53f7\u521d\u59cb\u5316\u65f6\uff0cinitializer_list \u6784\u9020\u51fd\u6570\u4f18\u5148\u7ea7\u6700\u9ad8\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <initializer_list>\r\n#include <vector>\r\n#include <string>\r\n#include <algorithm>\r\n#include <numeric>\r\n#include <cstddef>\r\n\r\n// ---- 1. \u57fa\u672c\u7528\u6cd5 ----\r\n\r\n// \u63a5\u53d7 initializer_list \u7684\u51fd\u6570\r\nvoid print_values(std::initializer_list<int> values) {\r\n    std::cout << "  [ ";\r\n    for (auto v : values) {\r\n        std::cout << v << " ";\r\n    }\r\n    std::cout << "] (\u5171 " << values.size() << " \u4e2a\u5143\u7d20)\\n";\r\n}\r\n\r\n// \u81ea\u5b9a\u4e49\u7c7b\u63a5\u53d7 initializer_list\r\nclass IntArray {\r\npublic:\r\n    IntArray(std::initializer_list<int> init)\r\n        : data_(init.begin(), init.end()) {\r\n        std::cout << "  IntArray \u4ece initializer_list \u6784\u9020, \u5927\u5c0f="\r\n                  << data_.size() << "\\n";\r\n    }\r\n\r\n    void print() const {\r\n        std::cout << "  IntArray: [ ";\r\n        for (int v : data_) std::cout << v << " ";\r\n        std::cout << "]\\n";\r\n    }\r\n\r\n    int sum() const {\r\n        return std::accumulate(data_.begin(), data_.end(), 0);\r\n    }\r\n\r\nprivate:\r\n    std::vector<int> data_;\r\n};\r\n\r\nvoid basic_usage() {\r\n    std::cout << "---- 1. \u57fa\u672c\u7528\u6cd5 ----\\n";\r\n\r\n    // \u51fd\u6570\u53c2\u6570\r\n    print_values({1, 2, 3, 4, 5});\r\n    print_values({10, 20});\r\n    print_values({}); // \u7a7a\u5217\u8868\r\n\r\n    // \u81ea\u5b9a\u4e49\u7c7b\r\n    IntArray arr = {10, 20, 30, 40, 50};\r\n    arr.print();\r\n    std::cout << "  \u603b\u548c: " << arr.sum() << "\\n";\r\n\r\n    // \u6807\u51c6\u5e93\u5bb9\u5668\r\n    std::vector<int> v = {1, 2, 3, 4, 5};\r\n    std::cout << "\\n  vector<int> \u7528\u82b1\u62ec\u53f7\u521d\u59cb\u5316, \u5927\u5c0f=" << v.size() << "\\n";\r\n\r\n    std::vector<std::string> names = {"\u5f20\u4e09", "\u674e\u56db", "\u738b\u4e94"};\r\n    std::cout << "  vector<string> \u7528\u82b1\u62ec\u53f7\u521d\u59cb\u5316, \u5927\u5c0f=" << names.size() << "\\n";\r\n\r\n    // auto \u63a8\u5bfc\r\n    auto il = {1, 2, 3}; // \u63a8\u5bfc\u4e3a std::initializer_list<int>\r\n    std::cout << "\\n  auto il = {1,2,3} \u7c7b\u578b\u5927\u5c0f: " << il.size() << "\\n";\r\n}\r\n\r\n// ---- 2. \u8fdb\u9636\u7528\u6cd5 ----\r\n\r\n// initializer_list \u7528\u4e8e\u5b9e\u73b0\u53ef\u53d8\u53c2\u6570\u7684\u7c7b\u578b\u5b89\u5168\u66ff\u4ee3\u65b9\u6848\r\nint max_of(std::initializer_list<int> values) {\r\n    return *std::max_element(values.begin(), values.end());\r\n}\r\n\r\nint min_of(std::initializer_list<int> values) {\r\n    return *std::min_element(values.begin(), values.end());\r\n}\r\n\r\n// \u914d\u7f6e\u7c7b \u2014\u2014 \u4f7f\u7528 initializer_list \u8bbe\u7f6e\u591a\u4e2a\u9009\u9879\r\nclass Config {\r\npublic:\r\n    struct Option {\r\n        std::string key;\r\n        std::string value;\r\n    };\r\n\r\n    Config(std::initializer_list<Option> options) {\r\n        for (const auto& opt : options) {\r\n            options_.push_back(opt);\r\n        }\r\n    }\r\n\r\n    void print() const {\r\n        std::cout << "  \u914d\u7f6e\u9879:\\n";\r\n        for (const auto& opt : options_) {\r\n            std::cout << "    " << opt.key << " = " << opt.value << "\\n";\r\n        }\r\n    }\r\n\r\nprivate:\r\n    std::vector<Option> options_;\r\n};\r\n\r\n// \u8d4b\u503c\u8fd0\u7b97\u7b26\u4e5f\u53ef\u4ee5\u4f7f\u7528 initializer_list\r\nclass DynamicArray {\r\npublic:\r\n    DynamicArray() = default;\r\n\r\n    DynamicArray(std::initializer_list<double> init)\r\n        : data_(init) {}\r\n\r\n    DynamicArray& operator=(std::initializer_list<double> init) {\r\n        data_.assign(init.begin(), init.end());\r\n        return *this;\r\n    }\r\n\r\n    void print() const {\r\n        std::cout << "  [ ";\r\n        for (double v : data_) std::cout << v << " ";\r\n        std::cout << "]\\n";\r\n    }\r\n\r\nprivate:\r\n    std::vector<double> data_;\r\n};\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n---- 2. \u8fdb\u9636\u7528\u6cd5 ----\\n";\r\n\r\n    // \u7c7b\u578b\u5b89\u5168\u7684\u53ef\u53d8\u53c2\u6570\r\n    std::cout << "max_of({3, 7, 2, 9, 1}): " << max_of({3, 7, 2, 9, 1}) << "\\n";\r\n    std::cout << "min_of({3, 7, 2, 9, 1}): " << min_of({3, 7, 2, 9, 1}) << "\\n";\r\n\r\n    // \u590d\u5408\u7c7b\u578b\u7684 initializer_list\r\n    std::cout << "\\n\u7ed3\u6784\u4f53\u7684 initializer_list:\\n";\r\n    Config cfg = {\r\n        {"host", "localhost"},\r\n        {"port", "8080"},\r\n        {"debug", "true"}\r\n    };\r\n    cfg.print();\r\n\r\n    // \u8d4b\u503c\u64cd\u4f5c\u7b26\u4e2d\u4f7f\u7528\r\n    std::cout << "\\n\u8d4b\u503c\u4e2d\u4f7f\u7528 initializer_list:\\n";\r\n    DynamicArray da;\r\n    da = {1.1, 2.2, 3.3};\r\n    da.print();\r\n    da = {10.0, 20.0};\r\n    da.print();\r\n\r\n    // \u904d\u5386 initializer_list\r\n    std::cout << "\\n\u76f4\u63a5\u904d\u5386\u82b1\u62ec\u53f7\u5217\u8868:\\n";\r\n    for (auto x : {10, 20, 30, 40}) {\r\n        std::cout << "  " << x;\r\n    }\r\n    std::cout << "\\n";\r\n}\r\n\r\n// ---- 3. \u5e38\u89c1\u9677\u9631\u4e0e\u6700\u4f73\u5b9e\u8df5 ----\r\n\r\nclass Ambiguous {\r\npublic:\r\n    // \u6784\u9020\u51fd\u65701: \u4e24\u4e2a int \u53c2\u6570\r\n    Ambiguous(int a, int b) {\r\n        std::cout << "  Ambiguous(int, int): a=" << a << ", b=" << b << "\\n";\r\n    }\r\n\r\n    // \u6784\u9020\u51fd\u65702: initializer_list\r\n    Ambiguous(std::initializer_list<int> il) {\r\n        std::cout << "  Ambiguous(initializer_list): \u5927\u5c0f=" << il.size() << "\\n";\r\n    }\r\n};\r\n\r\nvoid pitfalls() {\r\n    std::cout << "\\n---- 3. \u5e38\u89c1\u9677\u9631\u4e0e\u6700\u4f73\u5b9e\u8df5 ----\\n";\r\n\r\n    // \u9677\u96311: initializer_list \u6784\u9020\u51fd\u6570\u4f18\u5148\u7ea7\u66f4\u9ad8\r\n    std::cout << "\u9677\u96311: initializer_list \u6784\u9020\u51fd\u6570\u4f18\u5148!\\n";\r\n    Ambiguous a1(1, 2);    // \u8c03\u7528 (int, int)\r\n    Ambiguous a2{1, 2};    // \u8c03\u7528 initializer_list! \u4e0d\u662f (int, int)!\r\n    Ambiguous a3({1, 2});  // \u8c03\u7528 initializer_list\r\n\r\n    // vector \u7684\u7ecf\u5178\u9677\u9631\r\n    std::cout << "\\nvector \u7684\u7ecf\u5178\u4f8b\u5b50:\\n";\r\n    std::vector<int> v1(5, 1);   // 5 \u4e2a 1: [1, 1, 1, 1, 1]\r\n    std::vector<int> v2{5, 1};   // 2 \u4e2a\u5143\u7d20: [5, 1]\r\n    std::cout << "  vector<int>(5, 1) \u5927\u5c0f: " << v1.size() << " (5\u4e2a1)\\n";\r\n    std::cout << "  vector<int>{5, 1} \u5927\u5c0f: " << v2.size() << " (\u5143\u7d205\u548c1)\\n";\r\n\r\n    // \u9677\u96312: initializer_list \u7684\u5143\u7d20\u662f const \u7684\r\n    std::cout << "\\n\u9677\u96312: \u5143\u7d20\u4e0d\u53ef\u4fee\u6539\\n";\r\n    auto il = {1, 2, 3};\r\n    // *il.begin() = 10; // \u7f16\u8bd1\u9519\u8bef! \u5143\u7d20\u662f const int\r\n    std::cout << "  initializer_list \u7684\u5143\u7d20\u7c7b\u578b\u662f const T\\n";\r\n\r\n    // \u9677\u96313: initializer_list \u4e0d\u62e5\u6709\u6570\u636e\r\n    std::cout << "\\n\u9677\u96313: initializer_list \u53ea\u662f\u89c6\u56fe\\n";\r\n    std::cout << "  \u5e95\u5c42\u6570\u636e\u662f\u4e34\u65f6 const \u6570\u7ec4\\n";\r\n    std::cout << "  \u4e0d\u8981\u5728 initializer_list \u8d85\u51fa\u4f5c\u7528\u57df\u540e\u8bbf\u95ee\u5176\u5143\u7d20\\n";\r\n\r\n    // \u9677\u96314: \u7a84\u5316\u8f6c\u6362\u5728 {} \u4e2d\u662f\u88ab\u7981\u6b62\u7684\r\n    std::cout << "\\n\u9677\u96314: {} \u7981\u6b62\u7a84\u5316\u8f6c\u6362\\n";\r\n    // std::initializer_list<int> bad = {1.5, 2.7}; // \u7f16\u8bd1\u9519\u8bef! double->int \u7a84\u5316\r\n    std::cout << "  {1.5, 2.7} \u4e0d\u80fd\u521d\u59cb\u5316 initializer_list<int>\\n";\r\n\r\n    // \u6700\u4f73\u5b9e\u8df5\r\n    std::cout << "\\n\u6700\u4f73\u5b9e\u8df5:\\n";\r\n    std::cout << "  1. \u5bf9\u5bb9\u5668\u7c7b\u578b\uff0c\u63d0\u4f9b initializer_list \u6784\u9020\u51fd\u6570\\n";\r\n    std::cout << "  2. \u6ce8\u610f () \u548c {} \u521d\u59cb\u5316\u7684\u533a\u522b\\n";\r\n    std::cout << "  3. initializer_list \u6309\u503c\u4f20\u9012\uff08\u5b83\u672c\u8eab\u5f88\u8f7b\u91cf\uff09\\n";\r\n    std::cout << "  4. \u4e0d\u8981\u4ece\u51fd\u6570\u8fd4\u56de\u5c40\u90e8\u6570\u7ec4\u7684 initializer_list\\n";\r\n}\r\n\r\nint main() {\r\n    std::cout << "===== std::initializer_list - C++11 =====\\n\\n";\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n    return 0;\r\n}\n'})}),"\n",(0,s.jsx)(i.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,s.jsxs)(i.ul,{children:["\n",(0,s.jsx)(i.li,{children:(0,s.jsx)(i.a,{href:"https://en.cppreference.com/w/cpp/utility/initializer_list",children:"cppreference: std::initializer_list"})}),"\n"]})]})}function u(n={}){const{wrapper:i}={...(0,e.R)(),...n.components};return i?(0,s.jsx)(i,{...n,children:(0,s.jsx)(c,{...n})}):c(n)}},28453(n,i,t){t.d(i,{R:()=>l,x:()=>a});var r=t(96540);const s={},e=r.createContext(s);function l(n){const i=r.useContext(e);return r.useMemo(function(){return"function"==typeof n?n(i):{...i,...n}},[i,n])}function a(n){let i;return i=n.disableParentContext?"function"==typeof n.components?n.components(s):n.components||s:l(n.components),r.createElement(e.Provider,{value:i},n.children)}}}]);